import { useState } from "react";
import "./FraudAnalysis.css";

const FRAUD_QUEUE = [
  {
    id: "CHQ-2041", type: "Cheque",  bank: "YES Bank",    amount: "₹12,00,000", risk: 91,
    flags: ["High amount vs history", "New beneficiary", "Off-hours submission"],
    submitted: "07 Apr, 02:41 AM", ip: "103.21.58.x", device: "Mobile — Android",
    sig: 42, ocr: 99, ner: 97, status: "pending",
  },
  {
    id: "INV-0931", type: "Invoice", bank: "ICICI Bank",  amount: "₹18,500",   risk: 71,
    flags: ["GST mismatch", "Vendor not KYC'd"],
    submitted: "07 Apr, 10:15 AM", ip: "49.204.11.x", device: "Desktop — Chrome",
    sig: 88, ocr: 94, ner: 91, status: "pending",
  },
  {
    id: "CHQ-2039", type: "Cheque",  bank: "SBI",         amount: "₹85,000",   risk: 58,
    flags: ["Date discrepancy", "Handwriting confidence 61%"],
    submitted: "07 Apr, 09:52 AM", ip: "27.97.30.x", device: "Branch Scanner",
    sig: 73, ocr: 88, ner: 95, status: "review",
  },
  {
    id: "CHQ-2038", type: "Cheque",  bank: "Axis Bank",   amount: "₹3,40,000", risk: 84,
    flags: ["Signature mismatch", "Altered amount field suspected"],
    submitted: "07 Apr, 08:10 AM", ip: "106.51.90.x", device: "Mobile — iOS",
    sig: 31, ocr: 77, ner: 93, status: "rejected",
  },
  {
    id: "LNA-0214", type: "Loan",    bank: "Kotak Bank",  amount: "₹5,00,000", risk: 22,
    flags: [],
    submitted: "07 Apr, 11:20 AM", ip: "59.180.22.x", device: "Desktop — Firefox",
    sig: 95, ocr: 98, ner: 99, status: "approved",
  },
];

const SHAP_SETS = {
  "CHQ-2041": [
    { label: "High amount vs history",  val: -32, dir: "neg" },
    { label: "New beneficiary",         val: -18, dir: "neg" },
    { label: "Off-hours submission",    val: -14, dir: "neg" },
    { label: "OCR confidence",          val: +10, dir: "pos" },
    { label: "Device fingerprint",      val: -9,  dir: "neg" },
    { label: "IFSC valid",              val: +7,  dir: "pos" },
  ],
  "INV-0931": [
    { label: "GST number mismatch",     val: -22, dir: "neg" },
    { label: "Vendor not KYC verified", val: -19, dir: "neg" },
    { label: "Amount within range",     val: +14, dir: "pos" },
    { label: "OCR confidence",          val: +12, dir: "pos" },
    { label: "IP reputation",           val: -7,  dir: "neg" },
  ],
};

function RiskGauge({ score }) {
  const color = score >= 80 ? "var(--accent-red)" : score >= 50 ? "var(--accent-amber)" : "var(--accent-green)";
  const r = 52;
  const circ = 2 * Math.PI * r;
  const half = circ / 2;
  const fill = (score / 100) * half;
  return (
    <div className="risk-gauge-wrap">
      <svg width="130" height="72" viewBox="0 0 130 80">
        <path d="M 15 75 A 52 52 0 0 1 115 75" fill="none" stroke="rgba(255,255,255,0.07)" strokeWidth="8" strokeLinecap="round" />
        <path d="M 15 75 A 52 52 0 0 1 115 75" fill="none" stroke={color} strokeWidth="8" strokeLinecap="round"
          strokeDasharray={`${fill} ${half}`} />
      </svg>
      <div className="risk-gauge-val" style={{ color }}>
        <span className="mono" style={{ fontSize: 28, fontWeight: 700 }}>{score}</span>
        <span style={{ fontSize: 11, color: "var(--text-tertiary)" }}>RISK SCORE</span>
      </div>
    </div>
  );
}

function MiniBar({ val, color }) {
  return (
    <div style={{ display: "flex", alignItems: "center", gap: 8 }}>
      <div className="progress-bar" style={{ flex: 1 }}>
        <div className="progress-fill" style={{ width: `${val}%`, background: color }} />
      </div>
      <span className="mono" style={{ fontSize: 11, color, width: 34, textAlign: "right" }}>{val}%</span>
    </div>
  );
}

export default function FraudAnalysis() {
  const [selected, setSelected] = useState(FRAUD_QUEUE[0]);
  const [filter, setFilter] = useState("all");

  const shap = SHAP_SETS[selected.id] || SHAP_SETS["CHQ-2041"];
  const filtered = filter === "all" ? FRAUD_QUEUE : FRAUD_QUEUE.filter(d => d.status === filter);

  const riskColor = selected.risk >= 80 ? "var(--accent-red)" : selected.risk >= 50 ? "var(--accent-amber)" : "var(--accent-green)";

  return (
    <div className="fraud-page">
      {/* Left: Queue */}
      <div className="fraud-queue-panel">
        <div className="fraud-queue-header">
          <span className="card-title">Fraud Queue</span>
          <div style={{ display: "flex", gap: 6 }}>
            {["all","pending","review","rejected"].map(f => (
              <button key={f} className={`btn btn-ghost btn-sm ${filter === f ? "filter-active" : ""}`}
                onClick={() => setFilter(f)}>
                {f.charAt(0).toUpperCase() + f.slice(1)}
              </button>
            ))}
          </div>
        </div>
        <div className="fraud-list">
          {filtered.map(doc => (
            <div
              key={doc.id}
              className={`fraud-list-item ${selected?.id === doc.id ? "selected" : ""}`}
              onClick={() => setSelected(doc)}
            >
              <div className="fli-top">
                <span className="mono fli-id">{doc.id}</span>
                <span className={`badge ${doc.risk >= 80 ? "badge-red" : doc.risk >= 50 ? "badge-amber" : "badge-green"}`}>
                  {doc.risk}
                </span>
              </div>
              <div className="fli-bank">{doc.bank} · {doc.type}</div>
              <div className="fli-amount mono">{doc.amount}</div>
              {doc.flags.length > 0 && (
                <div className="fli-flags">
                  {doc.flags.slice(0, 2).map(f => (
                    <span key={f} className="fli-flag">{f}</span>
                  ))}
                  {doc.flags.length > 2 && (
                    <span className="fli-flag">+{doc.flags.length - 2} more</span>
                  )}
                </div>
              )}
            </div>
          ))}
        </div>
      </div>

      {/* Right: Detail */}
      {selected && (
        <div className="fraud-detail-panel animate-in">
          {/* Header */}
          <div className="card fraud-detail-header-card">
            <div style={{ display: "flex", alignItems: "flex-start", justifyContent: "space-between", gap: 20 }}>
              <div>
                <div style={{ display: "flex", alignItems: "center", gap: 12, marginBottom: 6 }}>
                  <span style={{ fontFamily: "var(--font-display)", fontSize: 20, fontWeight: 800, color: "var(--text-primary)" }}>
                    {selected.id}
                  </span>
                  <span className="badge badge-cyan">{selected.type}</span>
                  <span className={`badge ${
                    selected.status === "approved" ? "badge-green" :
                    selected.status === "rejected" ? "badge-red" :
                    selected.status === "review"   ? "badge-cyan" : "badge-amber"
                  }`}>{selected.status.toUpperCase()}</span>
                </div>
                <div style={{ fontSize: 13, color: "var(--text-secondary)" }}>{selected.bank}</div>
                <div style={{ fontFamily: "var(--font-mono)", fontSize: 22, fontWeight: 500, color: "var(--text-primary)", marginTop: 8 }}>
                  {selected.amount}
                </div>
              </div>
              <RiskGauge score={selected.risk} />
            </div>

            {/* ML confidence bars */}
            <div className="divider" />
            <div className="fraud-conf-grid">
              <div className="fraud-conf-item">
                <span className="conf-label">OCR Confidence</span>
                <MiniBar val={selected.ocr} color="var(--accent-cyan)" />
              </div>
              <div className="fraud-conf-item">
                <span className="conf-label">Sig. Auth.</span>
                <MiniBar val={selected.sig} color={selected.sig < 60 ? "var(--accent-red)" : "var(--accent-green)"} />
              </div>
              <div className="fraud-conf-item">
                <span className="conf-label">NER Accuracy</span>
                <MiniBar val={selected.ner} color="var(--accent-purple)" />
              </div>
            </div>
          </div>

          {/* Flags + Metadata side by side */}
          <div className="fraud-mid-row">
            {/* Flags */}
            <div className="card">
              <div className="card-header"><span className="card-title">Risk Flags</span></div>
              {selected.flags.length === 0 ? (
                <div style={{ color: "var(--accent-green)", fontSize: 13 }}>✓ No anomalies detected</div>
              ) : (
                <div className="flags-list">
                  {selected.flags.map(f => (
                    <div key={f} className="flag-row">
                      <span className="flag-icon">⚠</span>
                      <span className="flag-text">{f}</span>
                    </div>
                  ))}
                </div>
              )}
            </div>

            {/* Metadata */}
            <div className="card">
              <div className="card-header"><span className="card-title">Submission Context</span></div>
              <div className="meta-list">
                {[
                  ["Submitted",   selected.submitted],
                  ["IP Address",  selected.ip],
                  ["Device",      selected.device],
                ].map(([k, v]) => (
                  <div key={k} className="meta-row">
                    <span className="meta-key">{k}</span>
                    <span className="meta-val mono">{v}</span>
                  </div>
                ))}
              </div>
            </div>
          </div>

          {/* SHAP */}
          <div className="card">
            <div className="card-header">
              <span className="card-title">SHAP Explanation — Feature Contributions</span>
              <span className="badge badge-purple">RBI Compliant</span>
            </div>
            <p style={{ fontSize: 11, color: "var(--text-tertiary)", marginBottom: 18 }}>
              Why did the model give this risk score? Positive values lower risk; negative values raise it.
            </p>
            <div className="shap-chart">
              {shap.map(f => (
                <div key={f.label} className="shap-chart-row">
                  <span className="shap-chart-label">{f.label}</span>
                  <div className="shap-chart-bar-wrap">
                    <div className="shap-center-line" />
                    <div
                      className={`shap-chart-bar ${f.dir}`}
                      style={{ width: `${Math.abs(f.val)}%` }}
                    />
                  </div>
                  <span className={`shap-chart-val ${f.dir}`}>
                    {f.dir === "pos" ? "+" : ""}{f.val}
                  </span>
                </div>
              ))}
            </div>
          </div>

          {/* Actions */}
          {selected.status === "pending" || selected.status === "review" ? (
            <div className="fraud-actions">
              <button className="btn btn-primary">✓ Approve Document</button>
              <button className="btn btn-ghost">Send for Manual Review</button>
              <button className="btn btn-danger">✕ Reject — Flag as Fraud</button>
            </div>
          ) : (
            <div className="fraud-actions" style={{ opacity: 0.5 }}>
              <span className="badge badge-green" style={{ fontSize: 12, padding: "6px 14px" }}>
                Decision Recorded — {selected.status.toUpperCase()}
              </span>
            </div>
          )}
        </div>
      )}
    </div>
  );
}
